def escape(string):
    escaping = {
        '<': '&lt;',
        '>': '&gt;',
        '&': '&amp;'
    }

    escaped = ''
    for char in string:
        if char in escaping:
            escaped += escaping[char]
        else:
            escaped += char

    return escaped

