def ensure_even(numbers):
    evens = [n for n in numbers if n % 2 == 0]
    if not evens:
        return []

    min_even = min(evens)
    max_even = max(evens)

    result = []
    for num in numbers:
        if min_even <= num <= max_even:
            result.append(num)

    return result

