def calculate_profit(price, cost):
    profit = price - cost
    return profit

def calculate_average_profit(prices, costs):
    total_profit = 0
    num_days = len(prices)

    for i in range(num_days):
        profit = calculate_profit(prices[i], costs[i])
        total_profit += profit

    average_profit = total_profit / num_days
    return average_profit

def analyze_profit(data):
    prices = data['prices']
    costs = data['costs']

    average_profit = calculate_average_profit(prices, costs)
    if average_profit > 0:
        return f"Average profit: ${average_profit:.2f}. This is a great profit margin!"
    elif average_profit == 0:
        return f"No profit or loss. The market may be stable."
    else:
        return f"Average profit: ${average_profit:.2f}. This is a loss."

