def grant_wish(wish):
    wish = wish.lower()
    wish = re.sub(r'[^a-z\s]', '', wish)

    # Make sure the wish doesn't contain any bad words
    with open('bad_words.txt') as f:
        bad_words = set(f.read().splitlines())
    if any(bad_word in wish for bad_word in bad_words):
        return "Sorry, I can't fulfill that wish."

    # Grant the wish!
    if wish.startswith('i wish'):
        wish = re.sub(r'^i wish ', '', wish).strip()

        for i, word in enumerate(wish.split()):
            if i == 0:
                word = word.capitalize()
            elif word in ['for', 'of', 'in', 'with', 'by']:
                continue
            else:
                word = word.lower()
            wish = ' '.join([wish.split()[0], word]) + ' '.join(wish.split()[i+1:])
        return f"You're wish has been granted: {wish}!"
    else:
        return "Sorry, I can only grant wishes that start with 'I wish'."

import re

def get_phone_number(html):
    phone = re.search(r'\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}', html)
    if phone:
        return phone.group(0)
    else:
        return None

html = "<p>Call us at (555) 444-3210 for support.</p>"

phone_number = get_phone_number(html)
print(phone_number)

