def calculate_total(cart):
    total = 0
    for item in cart:
        total += item.price * item.quantity

    return total

def apply_discount(total):
    if total >= 100:
        total *= 0.85
    elif total >= 50:
        total *= 0.9

    return total

total = calculate_total(cart)
total = apply_discount(total)

