from jinja2 import Template

template_source = '''
&lt;h1&gt;Welcome {{ name }}&lt;/h1&gt;
&lt;p&gt;This is a personalized welcome email.&lt;/p&gt;
'''

def render_welcome(name):
    template = Template(template_source, autoescape=True)
    rendered = template.render(name=name)
    return rendered

class Order:
    def __init__(self, order_id, products, customer_name, shipping_address):
        self.order_id = order_id
        self.products = products
        self.customer_name = customer_name
        self.shipping_address = shipping_address

    def ship(self):
        print(f"Shipping to {self.shipping_address}")

    def cancel(self):
        print(f"Order {self.order_id} cancelled")

